const items = $input.all(); const http = this.helpers.httpRequest; const GKEY = $env.GEMINI_API_KEY; const out = [];
const MAX = 30;
const MAP = { CLIENT: 'Client final', ESN: 'ESN', RECRUTEMENT: 'Recrutement', INTERIM: 'Intérim', AUTRE: 'Autre' };
// Cibles non encore qualifiées, plafonnées pour rester sous le timeout 300s
const todo = items.filter(it => { const f = it.json; return (f.Entreprise || '').toString().trim() && !((f['Qualif IA'] || '').toString().trim()); }).slice(0, MAX);
for (const it of todo) {
  const f = it.json; const id = f.id; const nom = (f.Entreprise || '').toString().trim();
  const ville = (f.Ville || '').toString().trim(); const naf = (f['Code NAF'] || '').toString().trim();
  if (!nom || !id) continue;
  let label = '';
  try {
    if (GKEY) {
      const prompt = "Entreprise française : « " + nom + " »" + (ville ? " (" + ville + ")" : "") + (naf ? ", code NAF " + naf : "") + ". " +
        "Distingue les INTERMÉDIAIRES de services — ESN/SSII, conseil en ingénierie & assistance technique, cabinet de recrutement, agence d'intérim/emploi, portage salarial (ils vendent ou placent des consultants/candidats) — " +
        "des CLIENTS FINAUX (toute autre organisation qui consomme de l'IT pour son propre compte). " +
        "Réponds UNIQUEMENT par un mot : ESN, RECRUTEMENT, INTERIM, CLIENT, ou AUTRE. " +
        "Au moindre doute qu'il s'agit d'un intermédiaire de services ou de recrutement, ne réponds PAS CLIENT.";
      const r = await http({ method: 'POST', url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + encodeURIComponent(GKEY), body: { contents: [{ parts: [{ text: prompt }] }], tools: [{ google_search: {} }], generationConfig: { temperature: 0 } }, json: true, timeout: 10000 });
      const parts = (r && r.candidates && r.candidates[0] && r.candidates[0].content && r.candidates[0].content.parts) || [];
      const txt = parts.map(p => p.text || '').join(' ').toUpperCase();
      const m = txt.match(/CLIENT|RECRUTEMENT|INTERIM|ESN|AUTRE/);
      if (m) label = MAP[m[0]] || '';
    }
  } catch (e) { label = ''; }
  if (label) out.push({ json: { id: id, 'Qualif IA': label } });
}
return out;
